}

@Singleton
class ProductSearchController @Inject()(
  cc: ControllerComponents,
  dbConfigProvider: DatabaseConfigProvider
)(implicit ec: ExecutionContext)
  extends AbstractController(cc)
  with ProductJsonSupport {

  private val dbConfig = dbConfigProvider.get[JdbcProfile]
  import dbConfig.profile.api._

  implicit private val getProductResult: GetResult[Product] = GetResult { r =>
    Product(
      id = r.nextLong(),
      name = r.nextString(),
      description = r.nextStringOption(),
      category = r.nextStringOption(),
      brand = r.nextStringOption(),
      price = r.nextBigDecimal(),
      inStock = r.nextBoolean()
    )
  }

  def search: Action[AnyContent] = Action.async { request =>
    val params = request.queryString.view.mapValues(_.headOption).toMap

    val filters = scala.collection.mutable.ArrayBuffer.empty[SQLActionBuilder]
    val values = scala.collection.mutable.ArrayBuffer.empty[String]

    params.get("q").flatten.filter(_.nonEmpty).foreach { q =>
      filters += sql" AND (name LIKE ${"%" + q + "%"} OR description LIKE ${"%" + q + "%"})"
    }

    params.get("category").flatten.filter(_.nonEmpty).foreach { category =>
      filters += sql" AND category = $category"
    }

    params.get("brand").flatten.filter(_.nonEmpty).foreach { brand =>
      filters += sql" AND brand = $brand"
    }

    params.get("minPrice").flatten.filter(_.nonEmpty).foreach { minPrice =>
      scala.util.Try(BigDecimal(minPrice)).toOption.foreach { p =>
        filters += sql" AND price >= $p"
      }
    }

    params.get("maxPrice").flatten.filter(_.nonEmpty).foreach { maxPrice =>
      scala.util.Try(BigDecimal(maxPrice)).toOption.foreach { p =>
        filters += sql" AND price <= $p"
      }
    }

    params.get("inStock").flatten.filter(_.nonEmpty).foreach { inStock =>
      scala.util.Try(inStock.toBoolean).toOption.foreach { b =>
        filters += sql" AND inStock = $b"
      }
    }

    val whereFragment: SQLActionBuilder =
      if (filters.isEmpty) sql""
      else filters.reduceLeft(_ ++ _)

    val limit = params.get("limit").flatten.flatMap(s => scala.util.Try(s.toInt).toOption).getOrElse(50)
    val offset = params.get("offset").flatten.flatMap(s => scala.util.Try(s.toInt).toOption).getOrElse(0)

    val query =
      sql"SELECT id, name, description, category, brand, price, inStock FROM products WHERE 1=1" ++
        whereFragment ++
        sql" ORDER BY id DESC LIMIT $limit OFFSET $offset"

    dbConfig.db.run(query.as[Product]).map { products =>
      Ok(Json.toJson(products))
    }.recover {
      case e: Throwable =>
        InternalServerError(Json.obj("error" -> e.getMessage))
    }
  }
